/** Metadata for signal envelopes — production vs demo data source tagging. */
export function parseEmitDemoSignals(raw: string | boolean | undefined, defaultValue = false): boolean {
  if (typeof raw === 'boolean') return raw;
  if (raw === undefined || raw === '') return defaultValue;
  return String(raw).trim().toLowerCase() === 'true';
}

export function signalMetadataFromEmitDemo(emitDemoSignals?: string | boolean): Record<string, unknown> {
  return parseEmitDemoSignals(emitDemoSignals)
    ? { dataSource: 'demo' }
    : { dataSource: 'production', emitDemo: false };
}
